export function getLocation(slug: string): Location | undefined {
  return locations.find((l) => l.slug === slug);
}

export interface LocationGroup {
  borough: string;
  locations: Location[];
}

// Used by the "Areas We Cover" index page so all locations are browsable from
// one place, grouped by borough/district rather than one long flat list.
export function getLocationsGroupedByBorough(): LocationGroup[] {
  const groups = new Map<string, Location[]>();

  for (const location of locations) {
    const key = location.borough || 'Other';
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key)!.push(location);
  }

  return Array.from(groups.entries())
    .map(([borough, locs]) => ({
      borough,
      locations: [...locs].sort((a, b) => a.name.localeCompare(b.name)),
    }))
    .sort((a, b) => a.borough.localeCompare(b.borough));
}

// Postcode-area letters (e.g. "KT" from "KT3") are a good geographic proximity
// signal. We surface genuinely nearby areas on each location page so every page
// has a unique block of internal links and localised content rather than a pure
// template — this avoids the thin/duplicate-content SEO problem.
function postcodeArea(postcode?: string): string {
  return (postcode || '').replace(/[0-9].*$/, '').toUpperCase();
}

export function getNearbyLocations(slug: string, limit = 6): Location[] {
  const current = getLocation(slug);
  if (!current) return [];

  const currentArea = postcodeArea(current.postcode);
  const others = locations.filter((l) => l.slug !== current.slug);

  const scored = others
    .map((l) => {
      let score = 0;
      if (l.borough && l.borough === current.borough) score += 3;
      if (currentArea && postcodeArea(l.postcode) === currentArea) score += 2;
      return { location: l, score };
    })
    .filter((entry) => entry.score > 0)
    .sort((a, b) => b.score - a.score);

  const nearby = scored.map((entry) => entry.location);

  // Fall back to a few other London areas if a location has no scored neighbours,
  // so the "areas we also cover" block is never empty.
  if (nearby.length < limit) {
    for (const l of others) {
      if (nearby.length >= limit) break;
      if (!nearby.includes(l)) nearby.push(l);
    }
  }

  return nearby.slice(0, limit);
}

export interface LocationFAQ {
  q: string;
  a: string;
}

// Four differently-worded FAQ sets so the FAQPage schema isn't a byte-identical
// block repeated across all 81 location pages — each location gets one variant,
// chosen deterministically from its slug so the assignment is stable across builds.
const LOCATION_FAQ_VARIANTS: ((loc: Location) => LocationFAQ[])[] = [
  (loc) => [
    { q: `Do you offer same-day Mac repair in ${loc.name}?`, a: `Yes - we offer same-day callouts in ${loc.name} and surrounding areas. Book before 2pm and we can typically visit the same day.` },
    { q: 'Is there a callout charge?', a: `There is no callout charge for visits to ${loc.name}. You only pay for the repair itself, and only if we fix it.` },
    { q: `What areas near ${loc.name} do you also cover?`, a: `We cover all of ${loc.borough || loc.name} and surrounding areas. We travel across all of Greater London, so if you are nearby, we can almost certainly come to you.` },
    { q: 'What devices do you repair?', a: 'We repair MacBook Pro, MacBook Air, iMac, Mac Mini, all Windows laptops (HP, Dell, Lenovo, Asus, Acer), gaming PCs and more.' },
    { q: 'How do I book a repair?', a: `Call us on 0737 834 9222 or email info@werepairmac.co.uk. We will arrange a convenient time to visit your home or workplace in ${loc.name}.` },
  ],
  (loc) => [
    { q: `How quickly can an engineer reach ${loc.name}?`, a: `Most bookings in ${loc.name} are seen the same day if you call before 2pm. Evening and weekend visits are available too, so a repair fits around your schedule rather than the other way round.` },
    { q: `Will I be charged just for you to visit ${loc.name}?`, a: `No - there is no callout fee anywhere in ${loc.borough || loc.name}. You only pay for parts and labour, and nothing at all if we can't fix the problem.` },
    { q: 'What kind of computer problems do you handle?', a: 'Everything from cracked MacBook screens and failing batteries to Windows laptops that won\'t boot, slow PCs, virus infections and data recovery from failed drives.' },
    { q: `Do you cover the wider ${loc.borough || 'London'} area as well?`, a: `Yes - ${loc.name} sits within our regular coverage area, and we regularly visit the surrounding neighbourhoods on the same trip.` },
    { q: 'How do I arrange a visit?', a: `Phone 0737 834 9222 or email info@werepairmac.co.uk with a short description of the fault, and we'll confirm a time to come to you in ${loc.name}.` },
  ],
  (loc) => [
    { q: `What's the fastest way to get a repair booked in ${loc.name}?`, a: `Call 0737 834 9222 - most ${loc.name} callouts booked before 2pm are seen the same day, with no need to bring anything to a shop.` },
    { q: 'Do you charge extra for parts and labour separately, or is it all inclusive?', a: 'We quote labour (£100/hr) and any parts separately, upfront and before we start, so there are no surprises on the final bill.' },
    { q: `Is ${loc.name} within your standard service area?`, a: `Yes, ${loc.name} and the rest of ${loc.borough || 'the surrounding area'} are covered as standard, with no callout charge added to your bill.` },
    { q: 'What if the repair doesn\'t work?', a: 'Every repair carries a 90-day parts and labour warranty. If the same fault comes back, we return and fix it at no extra cost.' },
    { q: `Can you come to an office as well as a home in ${loc.name}?`, a: `Yes - we visit homes, offices and co-working spaces across ${loc.name} equally, and can work around meeting times if needed.` },
  ],
  (loc) => [
    { q: `Can someone come to my home in ${loc.name} rather than me bringing the laptop in?`, a: `Yes - that's the whole model. Our engineer travels to you in ${loc.name} and carries out most repairs on-site, in front of you.` },
    { q: 'Which brands and devices are you able to fix?', a: 'Mac and MacBook models of every generation, plus Windows laptops from HP, Dell, Lenovo, Asus and Acer, desktop PCs, and gaming consoles.' },
    { q: `Does it cost more because I'm in ${loc.name}?`, a: `No - pricing is the same across ${loc.borough || 'Greater London'}. There's no callout charge and no location-based surcharge.` },
    { q: 'What happens if you can\'t fix my device?', a: 'You pay nothing at all - no diagnostic fee, no callout charge. That is our No Fix, No Fee guarantee on every visit.' },
    { q: 'How far in advance do I need to book?', a: `Often not far at all - same-day visits in ${loc.name} are common if you call before 2pm, though evenings and weekends can be booked ahead if that suits you better.` },
  ],
];

function variantIndexFor(slug: string): number {
  let sum = 0;
  for (let i = 0; i < slug.length; i++) sum += slug.charCodeAt(i);
  return sum % LOCATION_FAQ_VARIANTS.length;
}

export function getLocationFaqs(location: Location): LocationFAQ[] {
  const variant = LOCATION_FAQ_VARIANTS[variantIndexFor(location.slug)];
  return variant(location);
}
